// scripts/check-contrast.mjs — run with: node scripts/check-contrast.mjs
import { chromium } from 'playwright';

const MIN_RATIO = 4.5; // WCAG AA for normal text

const browser = await chromium.launch();
const page = await browser.newPage();
await page.goto('http://localhost:5173');

// Send a test message to get both user and AI bubbles visible
await page.fill('textarea', 'Hello');
await page.click('[aria-label="Send message"]');
await page.waitForSelector('.message--ai', { timeout: 15000 });

// Check contrast for all message text elements
const violations = await page.evaluate((minRatio) => {
  const issues = [];
  document.querySelectorAll('.message__text, .message__bubble').forEach(el => {
    const style = window.getComputedStyle(el);
    const fg = style.color;
    const bg = style.backgroundColor;
    // NOTE: real contrast calculation requires a luminance formula
    // Use axe-core's checkContrastRatio or a library like 'color-contrast'
    // This is a placeholder showing the pattern
    issues.push({ element: el.className, fg, bg });
  });
  return issues;
}, MIN_RATIO);

console.log('Elements to verify contrast:', violations);
await browser.close();

// .lighthouserc.json
{
  "ci": {
    "assert": {
      "assertions": {
        "categories:accessibility": ["error", { "minScore": 0.95 }],
        "color-contrast": ["error", { "minScore": 1 }],
        "aria-live-region-content": ["error", { "minScore": 1 }],
        "button-name": ["error", { "minScore": 1 }],
        "label": ["error", { "minScore": 1 }]
      }
    }
  }
}

// js/error-handler.mjs
function showAIError(message) {
  // 1. Populate the assertive live region immediately
  const errorRegion = document.getElementById('error-region');
  errorRegion.textContent = message;

  // 2. Show the visible banner
  const banner = document.getElementById('error-banner');
  banner.style.display = 'block';

  // 3. Move keyboard focus to the banner so keyboard users notice it
  banner.focus();

  // 4. Clear after 10 seconds (longer than a toast — must be readable)
  setTimeout(() => {
    errorRegion.textContent = '';
    banner.style.display = 'none';
    // Return focus to the input field
    document.getElementById('chat-input').focus();
  }, 10000);
}

function dismissError() {
  document.getElementById('error-region').textContent = '';
  document.getElementById('error-banner').style.display = 'none';
  document.getElementById('chat-input').focus();
}

// js/chat-scroll.mjs
// Smart scroll: follow stream only if user is already at bottom
const messageList = document.getElementById('message-list');
let userScrolledUp = false;

messageList.addEventListener('scroll', () => {
  const threshold = 50; // px from bottom
  const distFromBottom = messageList.scrollHeight - messageList.scrollTop - messageList.clientHeight;
  userScrolledUp = distFromBottom > threshold;
});

export function appendAIChunk(chunk) {
  // Append chunk to the current AI message bubble
  const currentMsg = messageList.querySelector('.message--ai.streaming');
  if (currentMsg) {
    currentMsg.querySelector('.message__text').textContent += chunk;
  }

  // Only auto-scroll if user hasn't scrolled up
  if (!userScrolledUp) {
    messageList.scrollTop = messageList.scrollHeight;
  }
  // Do NOT move focus — focus stays where the user put it
}

export function finalizeAIMessage(messageEl) {
  messageEl.classList.remove('streaming');
  // Announce completion without moving focus
  const statusRegion = document.getElementById('thinking-indicator');
  statusRegion.textContent = '';  // clears "AI is thinking…" — announced as empty
  // The log region's aria-live="polite" already announced the full message
}
